function samplingProfile(len,pixelWidth){const mode=readMode.value,width=Math.max(1,Math.round(pixelWidth)),manyProcess=view==='process'&&currentSeries.length>PROCESS_TOP_N;if(mode==='trend'){const factor=view==='process'?(manyProcess?.1:.18):view==='fps'?.5:.45,buckets=Math.max(80,Math.min(len,Math.ceil(width*factor))),smooth=view==='fps'?3:5;return{mode,buckets,smooth}}const factor=view==='process'?(manyProcess?.18:.32):view==='fps'?.64:.52,buckets=Math.max(96,Math.min(len,Math.ceil(width*factor)));return{mode:'spike',buckets,envelope:true}}
