function decodeRleSeries(encoded,expectedLength){if(Array.isArray(encoded))return encoded;if(typeof encoded!=='string')return[];const target=Math.max(0,Number(expectedLength)||0),out=new Array(target);let outIndex=0,tokenStart=0;while(tokenStart<encoded.length&&outIndex<target){let tokenEnd=encoded.indexOf(';',tokenStart);if(tokenEnd<0)tokenEnd=encoded.length;if(tokenEnd>tokenStart){let star=encoded.indexOf('*',tokenStart);if(star<0||star>=tokenEnd)star=-1;const count=star>tokenStart?Number(encoded.slice(tokenStart,star)):1,valueText=star>tokenStart?encoded.slice(star+1,tokenEnd):encoded.slice(tokenStart,tokenEnd),value=valueText==='n'?null:Number(valueText);if(count>0){const next=Math.min(target,outIndex+count);out.fill(valueText==='n'?null:value,outIndex,next);outIndex=next}}tokenStart=tokenEnd+1}while(outIndex<target)out[outIndex++]=null;return out}
function decodeProcessSeriesForMetric(metric,matrix,idx){const raw=matrix[idx];if(DATA.process.codec!=='rle-v1')return raw||[];const key=`${metric}:${idx}`;if(processSeriesCache.has(key))return processSeriesCache.get(key);const decoded=decodeRleSeries(raw,(DATA.process.t||[]).length);if(processSeriesCache.size>320)processSeriesCache.clear();processSeriesCache.set(key,decoded);return decoded}
