function setTitle(){if(view==='fps'){viewTitle.textContent=DATA.notes.frameDataCaptured?'FPS GamePP 图表':'FPS 数据不可用';viewNote.textContent='FPS 按 1000 ms bucket 显示，raw PresentMon 统计仍作为源数据；蓝色面积、最小/最大/平均参考线和样本数提示保持可读。'}if(view==='cpuCore'){viewTitle.textContent='CPU 核心频率';viewNote.textContent='默认显示平均、最高和最低核心频率，避免多核心曲线重叠；提示仍列出每核心 MHz。'}if(view==='cpuVoltage'){viewTitle.textContent='CPU 电压 / Vcore';viewNote.textContent='整体 CPU 电压 / Vcore，单位 V，对齐 GamePP 的 CPU 电压指标；VID、SOC、Package、VBAT、VIN 不会作为 Vcore 使用。'}if(view==='cpuVid'){viewTitle.textContent='CPU 核心 VID（请求电压）';viewNote.textContent=(DATA.cpuVid&&DATA.cpuVid.note)||'VID 是 CPU 每核心请求/目标电压，不是真实 Vcore；它与 CPU 电压 / Vcore 分开显示。'}if(view==='perf'){viewTitle.textContent='性能频率';viewNote.textContent='CPU、GPU 和内存频率使用同一套深色面积折线样式，并在右侧显示当前标记。'}if(view==='system'){viewTitle.textContent='系统占用';viewNote.textContent='CPU、GPU、内存、VRAM 和 GPU 显存控制器统一使用 0-100% 的 Y 轴。'}if(view==='process'){viewTitle.textContent='后台进程';viewNote.textContent=`默认按记录到的峰值绘制前 ${PROCESS_TOP_N} 个进程；搜索会收窄曲线集合，表格保留更完整排序。`}if(view==='io'){viewTitle.textContent='IO / 温度';viewNote.textContent='不同单位拆成独立图表模式，避免温度、延迟、功耗和吞吐共用误导性的 Y 轴。'}}
function pickSeries(series,metric){return metric==='all'?series:series.filter(s=>s.key===metric)}
function buildSeries(){if(view==='fps'){currentTimes=DATA.fps.t||[];currentUnit='FPS';const all=[{key:'fps:avg',name:'平均 FPS',color:'#009dff',data:DATA.fps.avg||[]},{key:'fps:low1',name:'1% Low',color:'#dce6f0',data:DATA.fps.low1||[]},{key:'fps:low01',name:'0.1% Low',color:'#b7c4d2',data:DATA.fps.low01||[]}],map={avg:0,low1:1,low01:2};currentSeries=fpsMetric==='all'?all:[all[map[fpsMetric]||0]];return}if(view==='cpuCore'){const c=DATA.cpuCore||{},raw=c.series||[];currentTimes=c.t||[];currentUnit='MHz';currentSeries=cpuCoreMetric==='summary'?aggregateCoreSeries(raw,'cpuCore'):pickSeries(raw,cpuCoreMetric);return}if(view==='cpuVoltage'){const v=DATA.cpuVoltage||{},raw=v.available?(v.series||[]):[];currentTimes=v.available?(v.t||[]):[];currentUnit='V';currentSeries=raw;return}if(view==='cpuVid'){const v=DATA.cpuVid||{},raw=v.available?(v.series||[]):[];currentTimes=v.available?(v.t||[]):[];currentUnit='V';currentSeries=cpuVidMetric==='summary'?aggregateCoreSeries(raw,'cpuVid'):pickSeries(raw,cpuVidMetric);return}if(view==='perf'){currentTimes=DATA.system.t||[];currentUnit='MHz';const all=[{key:'perf:cpu',name:'CPU 频率',color:'#009dff',data:DATA.system.perf.cpuFreq||[]},{key:'perf:gpu',name:'GPU 频率',color:'#31e35f',data:DATA.system.perf.gpuClock||[]},{key:'perf:mem',name:'内存频率',color:'#ffd84a',data:DATA.system.perf.memClock||[]}],map={cpu:0,gpu:1,mem:2};currentSeries=perfMetric==='all'?all:[all[map[perfMetric]||0]];return}if(view==='system'){currentTimes=DATA.system.t||[];currentUnit='%';const all=[{key:'system:cpu',name:'CPU 占用',color:'#009dff',data:DATA.system.usage.cpu||[]},{key:'system:gpu',name:'GPU 占用',color:'#31e35f',data:DATA.system.usage.gpu||[]},{key:'system:gpuMem',name:'GPU 显存控制器',color:'#ffd84a',data:DATA.system.usage.gpuMem||[]},{key:'system:mem',name:'内存占用',color:'#d77cff',data:DATA.system.usage.mem||[]},{key:'system:vram',name:'VRAM 占用',color:'#65a7ff',data:DATA.system.usage.vram||[]}],map={cpu:0,gpu:1,gpuMem:2,mem:3,vram:4};currentSeries=systemMetric==='all'?all:[all[map[systemMetric]||0]];return}if(view==='io'){currentTimes=DATA.system.t||[];const io=DATA.system.io||{},sets={diskNet:{unit:'MB/s',series:[{key:'io:disk',name:'磁盘吞吐',color:'#009dff',data:io.disk||[]},{key:'io:net',name:'网络吞吐',color:'#31e35f',data:io.net||[]}]},diskLatency:{unit:'ms',series:[{key:'io:latency',name:'磁盘延迟',color:'#ffd84a',data:io.diskLatency||[]}]},power:{unit:'W',series:[{key:'io:power',name:'GPU 功耗',color:'#ff3b45',data:io.power||[]}]},temp:{unit:'°C',series:[{key:'io:temp',name:'GPU 温度',color:'#65a7ff',data:io.temp||[]}]}};const selected=sets[ioMetric]||sets.diskNet;currentUnit=selected.unit;currentSeries=selected.series;return}const idxs=visibleProcessIndexes();currentTimes=DATA.process.t||[];currentUnit=processMetric==='cpu'?'%':'MB';const matrix=processMetric==='cpu'?(DATA.process.cpu||[]):DATA.process.mem||[];currentSeries=idxs.map((idx,n)=>({key:`process:${processMetric}:${idx}`,name:DATA.process.names[idx],color:COLORS[n%COLORS.length],data:processSeriesData(matrix,idx)}))}
function emptyMessage(){if(view==='cpuVoltage')return (DATA.cpuVoltage&&DATA.cpuVoltage.reason)||'没有采集到 CPU 电压 / Vcore 样本；不会用 VID 伪造。';if(view==='cpuVid')return (DATA.cpuVid&&DATA.cpuVid.reason)||'没有采集到 CPU 核心 VID 样本；不会生成假数据。';if(view==='cpuCore')return (DATA.cpuCore&&DATA.cpuCore.reason)||'没有采集到 CPU 核心频率样本。';return '无可绘制数据。'}
function draw(){if(!DATA)return;setTitle();buildSeries();const{w,h,pw,ph}=chartDims(),range=visibleTimeRange();clearOverlay();lastRenderStats={raw:0,drawn:0,buckets:0};ctx.clearRect(0,0,w,h);const bg=ctx.createLinearGradient(0,0,w,h);bg.addColorStop(0,'#071321');bg.addColorStop(1,'#030812');ctx.fillStyle=bg;ctx.fillRect(0,0,w,h);if(!currentTimes.length||!currentSeries.length){ctx.fillStyle='#a9bac8';ctx.font='15px Segoe UI';ctx.fillText(emptyMessage(),PAD.l,PAD.t+24);legend.innerHTML='';updateModeStats();return}const rendered=[];let maxY=0;for(let si=0;si<currentSeries.length;si++){const points=getRenderablePoints(currentSeries[si],pw,range),len=Math.min(points.t.length,points.y.length);rendered.push({series:currentSeries[si],points,len});lastRenderStats.raw+=points.rawCount||0;lastRenderStats.drawn+=len;lastRenderStats.buckets+=points.bucketCount||0;for(let i=0;i<len;i++){const v=Number(points.y[i]);if(Number.isFinite(v)&&v>maxY)maxY=v}}if(view==='fps'){const fs=fpsFrameStats();for(const v of [fs.min,fs.average])if(v!==null&&v>maxY)maxY=v}const fixedMax=fixedYAxisMax();if(fixedMax!==null)maxY=fixedMax;if(!Number.isFinite(Number(maxY))||Number(maxY)<=0)maxY=1;if(fixedMax===null)maxY=maxY*1.08;function x(sec){return PAD.l+((Number(sec)-range.start)/range.span)*pw}function y(v){return PAD.t+ph-(Number(v)/maxY)*ph}const ticks=timeTicks(range,pw);ctx.save();ctx.beginPath();ctx.rect(PAD.l,PAD.t,pw,ph);ctx.clip();ctx.strokeStyle='rgba(155,205,235,.18)';ctx.lineWidth=1;for(let i=0;i<=6;i++){const yy=PAD.t+ph/6*i;ctx.beginPath();ctx.moveTo(PAD.l,yy);ctx.lineTo(PAD.l+pw,yy);ctx.stroke()}for(const tick of ticks){const xx=x(tick);ctx.beginPath();ctx.moveTo(xx,PAD.t);ctx.lineTo(xx,PAD.t+ph);ctx.stroke()}if(view==='fps')drawFpsArea(rendered.find(r=>r.series.key==='fps:avg')||rendered[0],x,y,PAD.t+ph);else rendered.slice(0,Math.min(4,rendered.length)).forEach((item,i)=>drawGameppArea(item,x,y,PAD.t+ph,i===0?.28:.13));for(let si=0;si<rendered.length;si++){const item=rendered[si],primary=(view==='fps'&&(item.series.key==='fps:avg'||rendered.length===1))||si===0,alpha=view==='fps'?(primary?1:.72):seriesAlpha(si);ctx.strokeStyle=view==='fps'&&primary?'#009dff':item.series.color;ctx.globalAlpha=alpha;ctx.lineWidth=view==='fps'?(primary?2.4:1.35):lineWidth(si);ctx.shadowColor=primary?rgba(item.series.color,.72):'transparent';ctx.shadowBlur=primary?8:0;ctx.beginPath();let started=false;for(let i=0;i<item.len;i++){const v=item.points.y[i];if(v===null||!Number.isFinite(Number(v))){started=false;continue}const xx=x(item.points.t[i]),yy=y(v);if(!started){ctx.moveTo(xx,yy);started=true}else ctx.lineTo(xx,yy)}ctx.stroke();ctx.globalAlpha=1;ctx.shadowBlur=0}ctx.restore();if(view==='fps')drawFpsReferenceLines(x,y,pw,PAD.t,PAD.t+ph);else drawGameppReferenceLines(rendered,x,y,pw,PAD.t,PAD.t+ph);ctx.strokeStyle='rgba(0,217,255,.34)';ctx.lineWidth=1;ctx.fillStyle='#a9bac8';ctx.font='12px Segoe UI';for(let i=0;i<=6;i++){const yy=PAD.t+ph/6*i;ctx.fillText(axisLabel(maxY-(maxY/6)*i,maxY),10,yy+4)}for(const tick of ticks){const xx=x(tick);ctx.fillText(formatTimeTick(tick,range.span),xx-24,h-18)}ctx.strokeStyle='rgba(0,217,255,.48)';ctx.strokeRect(PAD.l,PAD.t,pw,ph);ctx.fillStyle='rgba(239,247,255,.86)';ctx.font='12px Segoe UI';ctx.fillText(currentUnit,PAD.l+6,PAD.t+16);if(range.full&&range.span<range.full.span*.995){ctx.fillStyle='rgba(255,216,74,.94)';ctx.fillText(`${formatTimeTick(range.start,range.span)} - ${formatTimeTick(range.end,range.span)}`,PAD.l+96,PAD.t+16)}updateLegend();updateModeStats()}
function updateModeStats(){if(!modeStats)return;const label=readMode.options[readMode.selectedIndex]?.textContent||readMode.value,range=visibleTimeRange();const raw=lastRenderStats.raw||0,drawn=lastRenderStats.drawn||0,buckets=lastRenderStats.buckets||0,windowText=range.span<range.full.span*.995?`${formatTimeTick(range.start,range.span)}-${formatTimeTick(range.end,range.span)}`:'全范围';modeStats.textContent=`${label} | ${windowText} | 已绘制 ${drawn.toLocaleString()} / 原始 ${raw.toLocaleString()} 点 | 分桶 ${buckets.toLocaleString()}`}
function redraw(){tooltip.style.opacity=0;chartBox.classList.add('switching');window.setTimeout(()=>{draw();window.requestAnimationFrame(()=>chartBox.classList.remove('switching'))},70)}
function nearestIndex(times,sec){if(!times.length)return 0;if(sec<=Number(times[0]))return 0;let lo=0,hi=times.length-1;if(sec>=Number(times[hi]))return hi;while(hi-lo>1){const mid=(lo+hi)>>1;if(Number(times[mid])<sec)lo=mid;else hi=mid}return Math.abs(Number(times[lo])-sec)<=Math.abs(Number(times[hi])-sec)?lo:hi}
function sourceRowsForTooltip(idx){if(view==='cpuCore'&&cpuCoreMetric==='summary')return ((DATA.cpuCore&&DATA.cpuCore.series)||[]).map(s=>({name:s.name,value:(s.data||[])[idx],color:s.color}));if(view==='cpuVid'&&cpuVidMetric==='summary')return ((DATA.cpuVid&&DATA.cpuVid.series)||[]).map(s=>({name:s.name,value:(s.data||[])[idx],color:s.color}));return currentSeries.map(s=>({name:s.name,value:s.data[idx],color:s.color}))}
function hover(evt){const{pw,ph}=chartDims(),rect=chartBox.getBoundingClientRect(),mx=evt.clientX-rect.left,my=evt.clientY-rect.top;if(mx<PAD.l||mx>PAD.l+pw||my<PAD.t||my>PAD.t+ph){tooltip.style.opacity=0;clearOverlay();return}const range=visibleTimeRange(),sec=range.start+(mx-PAD.l)/pw*range.span,idx=nearestIndex(currentTimes,sec);clearOverlay();octx.strokeStyle='rgba(255,255,255,.62)';octx.lineWidth=1;octx.beginPath();octx.moveTo(mx,PAD.t);octx.lineTo(mx,PAD.t+ph);octx.stroke();let html=`<b>${formatTimeTick(currentTimes[idx],range.span)}</b><br>`;if(view==='fps'){const fps=DATA.fps||{},samples=(fps.samples||[])[idx],bucketMs=Number(fps.bucketMs)||1000,rows=[{name:'平均 FPS',value:(fps.avg||[])[idx],color:'#009dff'},{name:'1% Low',value:(fps.low1||[])[idx],color:'#dce6f0'},{name:'0.1% Low',value:(fps.low01||[])[idx],color:'#b7c4d2'}];html+=rows.filter(r=>r.value!==null&&Number.isFinite(Number(r.value))).map(r=>`<span style='color:${r.color}'>&#9632;</span> ${esc(r.name)}：${n(r.value,2)} FPS`).join('<br>');html+=`<br>样本数：${samples??'无数据'} 帧，bucketMs=${bucketMs} ms`}else{let rows=[];if(view==='process'){const q=processSearch.value.trim().toLowerCase(),cacheKey=`${processMetric}|${q}|${idx}|${currentSeries.length}`;if(processHoverCache.has(cacheKey))rows=processHoverCache.get(cacheKey);else{for(const s of currentSeries){const v=s.data[idx];if(v!==null&&Number.isFinite(Number(v)))rows.push({name:s.name,value:v,color:s.color})}rows.sort((a,b)=>Number(b.value)-Number(a.value));rows=rows.slice(0,26);if(processHoverCache.size>4000)processHoverCache.clear();processHoverCache.set(cacheKey,rows)}}else rows=sourceRowsForTooltip(idx).filter(r=>r.value!==null&&Number.isFinite(Number(r.value)));const digits=unitDigits();html+=rows.map(r=>`<span style='color:${r.color}'>&#9632;</span> ${esc(r.name)}：${n(r.value,digits)} ${currentUnit}`).join('<br>')}tooltip.innerHTML=html;const maxLeft=Math.max(8,rect.width-300);tooltip.style.left=Math.min(maxLeft,Math.max(8,mx+14))+'px';tooltip.style.top=Math.max(8,my+14)+'px';tooltip.style.opacity=1}
function scheduleHover(evt){pendingHoverEvent=evt;if(hoverFrame)return;hoverFrame=window.requestAnimationFrame(()=>{hoverFrame=0;const e=pendingHoverEvent;pendingHoverEvent=null;if(e)hover(e)})}
function plotPoint(evt){const{pw,ph}=chartDims(),rect=chartBox.getBoundingClientRect(),mx=evt.clientX-rect.left,my=evt.clientY-rect.top;return{mx,my,pw,ph,inside:mx>=PAD.l&&mx<=PAD.l+pw&&my>=PAD.t&&my<=PAD.t+ph}}
function zoomChart(evt){const p=plotPoint(evt);if(!p.inside)return;evt.preventDefault();const range=visibleTimeRange(),ratio=(p.mx-PAD.l)/p.pw,focus=range.start+ratio*range.span,full=range.full,minSpan=Math.max(.5,full.span/2000),zoom=evt.deltaY<0?.78:1.28,newSpan=Math.max(minSpan,Math.min(full.span,range.span*zoom)),nextStart=focus-newSpan*ratio;setTimeView(nextStart,nextStart+newSpan);hover(evt)}
function startPan(evt){if(evt.button!==0)return;const p=plotPoint(evt);if(!p.inside)return;const range=visibleTimeRange();dragState={x:evt.clientX,start:range.start,end:range.end,span:range.span,moved:false};chartBox.classList.add('dragging');tooltip.style.opacity=0;evt.preventDefault()}
function movePan(evt){if(!dragState){scheduleHover(evt);return}const{pw}=chartDims();const dx=evt.clientX-dragState.x;if(Math.abs(dx)>2)dragState.moved=true;const delta=(-dx/pw)*dragState.span;setTimeView(dragState.start+delta,dragState.end+delta)}
function endPan(){if(!dragState)return;dragState=null;chartBox.classList.remove('dragging')}
function exportChartPng(){draw();const out=document.createElement('canvas'),scale=2,w=1600,h=1000;out.width=w*scale;out.height=h*scale;const c=out.getContext('2d');c.scale(scale,scale);const bg=c.createLinearGradient(0,0,w,h);bg.addColorStop(0,'#030812');bg.addColorStop(1,'#071321');c.fillStyle=bg;c.fillRect(0,0,w,h);c.fillStyle='#eff7ff';c.font='700 30px Segoe UI';c.fillText((DATA.target&&(DATA.target.displayName||DATA.target.processName))||'FrameScope',42,54);c.fillStyle='#a9bac8';c.font='15px Segoe UI';c.fillText(`${viewTitle.textContent} | ${readMode.options[readMode.selectedIndex]?.textContent||readMode.value} | ${DATA.run.durationLabel}`,42,84);c.fillText(modeStats.textContent||'',42,108);canvasRoundRect(c,42,130,1516,820,26);c.fillStyle='#071321';c.fill();c.save();canvasRoundRect(c,42,130,1516,820,26);c.clip();c.drawImage(canvas,0,0,canvas.width,canvas.height,42,130,1516,820);c.restore();c.strokeStyle='rgba(0,217,255,.58)';c.lineWidth=2;canvasRoundRect(c,42,130,1516,820,26);c.stroke();const a=document.createElement('a');a.download=`framescope-${view}-${readMode.value}.png`;a.href=out.toDataURL('image/png');a.click()}
if(DATA){syncVidTab();document.querySelectorAll('.tab').forEach(btn=>btn.addEventListener('click',()=>{document.querySelectorAll('.tab').forEach(b=>b.classList.remove('active'));btn.classList.add('active');view=btn.dataset.view;processHoverCache.clear();legendKey='';setOptions();redraw()}));metricSelect.addEventListener('change',()=>{if(view==='fps')fpsMetric=metricSelect.value;else if(view==='perf')perfMetric=metricSelect.value;else if(view==='system')systemMetric=metricSelect.value;else if(view==='io')ioMetric=metricSelect.value;else if(view==='cpuCore')cpuCoreMetric=metricSelect.value;else if(view==='cpuVoltage'){}else if(view==='cpuVid')cpuVidMetric=metricSelect.value;else processMetric=metricSelect.value;processHoverCache.clear();legendKey='';redraw()});processSearch.addEventListener('input',scheduleProcessSearchDraw);readMode.addEventListener('change',()=>{renderCache.clear();processHoverCache.clear();redraw()});widthScale.addEventListener('input',applyWidth);document.getElementById('fitWidth').addEventListener('click',()=>{widthScale.value=1;applyWidth()});document.getElementById('resetView').addEventListener('click',resetTimeView);document.getElementById('exportPng').addEventListener('click',exportChartPng);chartBox.addEventListener('wheel',zoomChart,{passive:false});chartBox.addEventListener('mousedown',startPan);chartBox.addEventListener('mousemove',movePan);window.addEventListener('mouseup',endPan);chartBox.addEventListener('mouseleave',()=>{if(!dragState){tooltip.style.opacity=0;clearOverlay()}});window.addEventListener('resize',()=>applyWidth());if(window.ResizeObserver){resizeObserver=new ResizeObserver(()=>{renderCache.clear();processHoverCache.clear();resizeCanvas()});resizeObserver.observe(chartBox)}initStatic();setOptions();applyWidth();window.setTimeout(warmProcessTopSeries,0)}
</script>
